function scaleFills(ratio){
		//scales the fills to be equivalent areas based on percentages of deaths
		var fillScale = d3.scaleLinear() //interpolation of the equivalent area problem which is technically unsolvable analytically
			.domain([0, .1, .2, .3, .4, .45, .5])
			.range([0, .3128, .507955, .680056, .8419, .92102, 1])
		if(ratio > .5){
			return (1 - fillScale( ratio - .5)) ;
		}
		else{ 
			return fillScale( .5 - ratio );
		};
}

//Update map on zoom/pan
function zoomed() {
  features.attr("transform", d3.event.transform);
  nodes.attr("transform", d3.event.transform);
}

