d3.select("#submitDate").on("click",function(d){
	features.attr("transform", d3.zoomIdentity);
	var minDate = new Date(document.getElementById("minDate").value);
	var maxDate = new Date(document.getElementById("maxDate").value);
	var filter = function(d) { return (d.date >= minDate && d.date <= maxDate); };
	drawCircles(gunData, filter, "All Cities");
});



function drawMap(gunData){
	var legend = svg.selectAll('.legend')
		.data([
			{color: 'deepskyblue', offset: 50, title: "Male"},
			{color : 'mediumvioletred', offset: 80, title: "Female"}
			])
		.enter()
			.append("g")
			.attr("class","legend");
	legend.append('circle')
		.attr('cx', width - 80)
		.attr('cy', function(d) {return height - d.offset;})
		.attr('fill', function(d) {return d.color;})
		.attr('r', 10)
		.attr('fill-opacity', .8)
		.attr("style","cursor:default;");
	legend.append('text')
		.attr('text-anchor', "start")
		.attr('x', width - 65)
		.attr('y', function(d) {return height - d.offset + 5;})
		.attr("font-size", "1.2em")
		.attr('font-family', 'cursive')
		.attr("style","cursor:default;")
		.text( function(d) {return d.title;});

	features.selectAll("path")
		.data(geoData.features)
		.enter()
		.append("path")
		.attr("d",path);
		
	resetButton = svg.selectAll(".reset")
		.data([{x: 10, y: 30, width: 60, height: 25}])
		.enter()
		.append('g')
		.attr("class","reset");
		
	resetButton.append("rect")
		.attr('x', function(d){ return d.x })
		.attr('y', function(d){ return height - d.y })
		.attr('width', function(d){ return d.width })
		.attr('height', function(d){ return d.height })
		.attr('style', 'fill:gray;stroke:black;stroke-width:1;fill-opacity:.5');
	resetButton.append("text")
			.attr('text-anchor','middle')
			.attr('x', function(d){ return d.x + d.width/2; })
			.attr('y', function(d){ return height - d.y + d.height/1.5; })
			.attr("font-size", "1.2em")
			.attr('font-family', 'cursive')
			.text("Reset");
		
	resetButton.on("click", function(){
		features.attr("transform", d3.zoomIdentity);
		d3.selectAll(".nodes").attr("transform", d3.zoomIdentity);
		drawCircles(gunData);
	});
	
}

function drawCircles(gunData, filter = null, cityName = "All Cities", isFirst = false){
		//creates a map object of the data where the keys are city names and the various stuff is includes
	if(filter != null){
		gunData = gunData.filter(filter);
	}
	var dataMap = d3.nest()
		.key(function(d) {return d.city;})
		.rollup(function(v) {return {
							percentMale: d3.sum( v, function(d) {return d.isMale;})/v.length,
							lat: d3.mean( v, function(d) {return d.lat}),
							lon: d3.mean( v, function(d) {return d.lng}),
							averageAge: d3.mean( v, function(d) {return d.age;}),
							count: v.length,};})
		.map(gunData, d3.map);
		
	//projects coordinates and filters out bad values
	dataMap.each(function(value,key){
		let coords = projection([value.lon, value.lat]);
		if (coords != null){
			value.lon = coords[0];
			value.lat = coords[1];
			value.city = key;
		} else{ dataMap.remove(key); }
	});
	
	//scale the max value to 50 so we can make the circles we plot manageable
	var radScale = d3.scaleLinear()
		.domain([0, d3.max( dataMap.values(), function(d) {return d.count;})])
		.range([0, 60]);

	//This is actually faster than updating and more consistent
	d3.selectAll(".nodes").remove();
	d3.selectAll("linearGradient").remove();
	
	var nodes = svg.selectAll(".nodes")
		.data(dataMap.values(), function(d){return d.city;})
		.enter()
		.append('g')
		.attr('class','nodes');
	
	var gradient = defs.selectAll("linearGradient")
		.data(dataMap.values(),function(d){return d.city;})
		.enter()
		.append("linearGradient");
	gradient.attr("id", function(d) { return "gradient-" + d.percentMale;} )
		.attr("x1", "0%")
		.attr("y1", "0%")
		.attr("x2", "0%")
		.attr("y2", "100%");
	//Define the gradient colors
	gradient.append("stop")
		.attr("offset", "0")
		.attr("class","start")
		.attr("stop-color", "MediumVioletRed")
		.attr("stop-opacity", 1);
	gradient.append("stop")
		.attr("class","stop")
		.attr("offset", function (d) {return scaleFills(d.percentMale -.01).toString();} )
		.attr("stop-color", "mediumvioletred")
		.attr("stop-opacity", 1);
	gradient.append("stop")
		.attr("offset", function (d) {return scaleFills(d.percentMale).toString();} )
		.attr("class","start")
		.attr("stop-color", "deepskyblue")
		.attr("stop-opacity", 1);
	gradient.append("stop")
		.attr("class","stop")
		.attr("offset", "1")
		.attr("stop-color", "deepskyblue")
		.attr("stop-opacity", 1);
	
	nodes.append("circle")
		.attr("class","enter")
		.attr("cx", function(d) { return d.lon; })
		.attr("cy", function(d) { return d.lat; })
		.attr("r", function(d) {
			if(d.city == "Chicago"){
				console.log(radScale(d.count));
			}
			return radScale(d.count); 
		})
		.attr("fill-opacity", .4)
		.attr("stroke-width", ".1")
		.attr("stroke", "black")
		.attr('fill', function(d) 
			{ return "url(#gradient-" + d.percentMale + ")";} 
		)
	nodes.append("text")
		.attr("class","enter")
		.attr("font-size", function(d) { return (radScale(d.count)/3) + "px"; })
		.attr("color", "black")
		.attr("text-anchor", "middle")
		.attr("x", function(d) { return d.lon; })
		.attr("y", function(d) { return d.lat + (radScale(d.count)/7); })
		.attr("opacity", 0)
		.text( function(d) { return d.city; } );
	

	d3.selectAll(".nodes").on("mouseover", function(){
			d3.select(this).selectAll("text")
				.attr("opacity", 1);
			d3.select(this).selectAll("circle")
				.attr("fill-opacity", .9);
		})	
		.on("mouseout", function(){
			d3.select(this).selectAll("text")
				.attr("opacity", 0);
			d3.select(this).selectAll("circle")
				.attr("fill-opacity", .4);
		})
		.on("click", function(){
			var city = d3.select(this).select("text").datum().city;
			drawHistogram(gunData, city);
		});
		
	var zoom = d3.zoom()
    .scaleExtent([1, 40])
    .translateExtent([[-100, -100], [width + 90, height + 100]])
    .on("zoom", function(){
				features.attr("transform", d3.event.transform);
				d3.selectAll(".nodes").attr("transform", d3.event.transform);
				});
	
	svg.call(zoom);
	
	drawHistogram( gunData, cityName);		
	
}

